import{_ as e,o as l,c as r,ag as i}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"bamdra-openclaw-memory","description":"Bamdra 面向 OpenClaw 的首个产品，提供话题连续性、持久化事实召回与生产级上下文装配。","frontmatter":{"title":"bamdra-openclaw-memory","description":"Bamdra 面向 OpenClaw 的首个产品，提供话题连续性、持久化事实召回与生产级上下文装配。"},"headers":[],"relativePath":"zh/guide/openclaw-topic-memory.md","filePath":"zh/guide/openclaw-topic-memory.md","lastUpdated":null}'),o={name:"zh/guide/openclaw-topic-memory.md"};function t(h,a,n,d,c,m){return l(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="bamdra-openclaw-memory" tabindex="-1">bamdra-openclaw-memory <a class="header-anchor" href="#bamdra-openclaw-memory" aria-label="Permalink to &quot;bamdra-openclaw-memory&quot;">​</a></h1><h2 id="产品概述" tabindex="-1">产品概述 <a class="header-anchor" href="#产品概述" aria-label="Permalink to &quot;产品概述&quot;">​</a></h2><p><code>bamdra-openclaw-memory</code> 是 Bamdra OpenClaw 记忆套件中的主插件。它围绕真实协作中的核心问题来设计：话题切换、中断恢复、稳定事实保存、摘要更新，以及如何让上下文在生产环境中保持足够精简。</p><p>一句话理解，它就是 OpenClaw 的上下文调度层: 帮助系统判断当前应该延续什么、切换什么、召回什么，而不是让用户频繁学习一套显式的“记忆操作方式”。</p><p>它可以独立运行；同时通过 npm 安装时，也能自动补齐 <code>bamdra-user-bind</code>，这样用户不需要为了身份层再手工执行第二次安装。</p><h2 id="它解决的核心问题" tabindex="-1">它解决的核心问题 <a class="header-anchor" href="#它解决的核心问题" aria-label="Permalink to &quot;它解决的核心问题&quot;">​</a></h2><p>在没有记忆系统的情况下，OpenClaw 很容易在长会话里丢失重点。用户需要反复重复背景，稳定事实无法持续复用，之前做出的判断也容易在中断之后被冲散。<code>bamdra-openclaw-memory</code> 解决的正是这个断层，让 OpenClaw 从单轮回答能力，升级为可持续协作能力。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><h3 id="规则-自然语言驱动的双线保障" tabindex="-1">规则 + 自然语言驱动的双线保障 <a class="header-anchor" href="#规则-自然语言驱动的双线保障" aria-label="Permalink to &quot;规则 + 自然语言驱动的双线保障&quot;">​</a></h3><p>插件的核心上下文调度机制，是两条线一起工作：</p><ul><li>一条线用明确规则做兜底，处理显式切换、稳定事实、边界控制和关键触发条件</li><li>一条线用自然语言语义做判断，让 topic 切换、上下文恢复和事实召回更贴近日常对话</li></ul><p>这使得它既不会僵硬到只能识别固定命令，也不会松散到完全不可预测。</p><h3 id="话题连续性" tabindex="-1">话题连续性 <a class="header-anchor" href="#话题连续性" aria-label="Permalink to &quot;话题连续性&quot;">​</a></h3><p>把不同分支隔离开来，并在用户回到旧话题时恢复正确上下文。</p><h3 id="持久化事实召回" tabindex="-1">持久化事实召回 <a class="header-anchor" href="#持久化事实召回" aria-label="Permalink to &quot;持久化事实召回&quot;">​</a></h3><p>把偏好、路径、约束、决策和引用信息保存下来，供后续继续使用。</p><h3 id="紧凑上下文装配" tabindex="-1">紧凑上下文装配 <a class="header-anchor" href="#紧凑上下文装配" aria-label="Permalink to &quot;紧凑上下文装配&quot;">​</a></h3><p>围绕当前活跃分支生成更精炼的 prompt，而不是不断重放全部历史。</p><h3 id="显式工具控制" tabindex="-1">显式工具控制 <a class="header-anchor" href="#显式工具控制" aria-label="Permalink to &quot;显式工具控制&quot;">​</a></h3><p>在需要的时候，operator 可以显式查看 topic、切换分支、保存事实、刷新摘要和搜索记忆。</p><h2 id="它带来的产品价值" tabindex="-1">它带来的产品价值 <a class="header-anchor" href="#它带来的产品价值" aria-label="Permalink to &quot;它带来的产品价值&quot;">​</a></h2><ul><li>让长会话真正可持续</li><li>降低重复背景说明的成本</li><li>让环境信息和项目事实可以长期复用</li><li>为 OpenClaw 从实验阶段走向生产使用提供更清晰的基础</li></ul><h2 id="架构特点" tabindex="-1">架构特点 <a class="header-anchor" href="#架构特点" aria-label="Permalink to &quot;架构特点&quot;">​</a></h2><ul><li>默认使用 SQLite 作为事实源</li><li>默认使用内存缓存作为热路径</li><li>插件层保持轻量，便于接入 OpenClaw</li><li>通过摘要与 topic 状态控制上下文规模</li></ul><h2 id="适合哪些团队" tabindex="-1">适合哪些团队 <a class="header-anchor" href="#适合哪些团队" aria-label="Permalink to &quot;适合哪些团队&quot;">​</a></h2><p>如果你的团队符合下面这些特征，这个产品会很适合：</p><ul><li>使用 OpenClaw 进行长周期协作</li><li>会频繁回到之前讨论过的主题</li><li>希望稳定事实只保存一次、长期复用</li><li>既需要自动恢复，也希望保留人工控制能力</li></ul><h2 id="github" tabindex="-1">GitHub <a class="header-anchor" href="#github" aria-label="Permalink to &quot;GitHub&quot;">​</a></h2><ul><li>GitHub 首页: <a href="https://github.com/bamdra" target="_blank" rel="noreferrer">github.com/bamdra</a></li><li>仓库: <a href="https://github.com/bamdra/bamdra-openclaw-memory" target="_blank" rel="noreferrer">bamdra/bamdra-openclaw-memory</a></li></ul><h2 id="建议继续阅读" tabindex="-1">建议继续阅读 <a class="header-anchor" href="#建议继续阅读" aria-label="Permalink to &quot;建议继续阅读&quot;">​</a></h2><ul><li><a href="/zh/guide/installation">安装部署</a></li><li><a href="/zh/guide/best-practices">最佳实践</a></li><li><a href="/zh/guide/faq">常见问题</a></li><li><a href="/zh/guide/downloads">下载资源</a></li></ul>',31)])])}const b=e(o,[["render",t]]);export{u as __pageData,b as default};
